const items = $input.all();
const packet = $('Set Fields — Topic Locks Proof').first().json;

function pickCharge(preferredIds, preferredRoles, fallbackIndex) {
  const found = items.find((item) => {
    const j = item.json || {};
    const id = String(j.charge_id || '');
    const role = String(j.charge_role || '');
    return preferredIds.includes(id) || preferredRoles.includes(role);
  });
  return found || items[fallbackIndex] || null;
}

function usable(item) {
  if (!item || !item.json) return false;
  const j = item.json;
  const status = String(j.status || '').toLowerCase();
  const hasFindings = Boolean(
    j.findings_summary ||
      j.findings ||
      j.gaps_risks ||
      (Array.isArray(j.sources_claims) && j.sources_claims.length) ||
      (typeof j.output === 'string' && j.output.trim())
  );
  return (status === 'done' || status === 'pass') && hasFindings;
}

const chargeA = pickCharge(['A', 'a'], ['research_a', 'A'], 0);
const chargeB = pickCharge(['B', 'b', 'research-b'], ['B', 'research_b', 'adversarial_gaps'], 1);

const aOk = usable(chargeA);
const bOk = usable(chargeB);
const outcome = aOk && bOk ? 'pass' : 'block';

let reason;
if (outcome === 'pass') {
  reason = 'Both charges returned usable status and findings';
} else {
  const parts = [];
  if (!aOk) parts.push('Charge A missing usable status/findings');
  if (!bOk) parts.push('Charge B missing usable status/findings');
  if (items.length < 2) parts.push('Merge returned fewer than two charge items');
  reason = parts.join('; ') || 'Merge proof failed';
}

const aSnippet = String(
  (chargeA && (chargeA.json.findings_summary || chargeA.json.findings || chargeA.json.status)) || ''
).slice(0, 48);
const bSnippet = String(
  (chargeB && (chargeB.json.findings || chargeB.json.gaps_risks || chargeB.json.status)) || ''
).slice(0, 48);
const merge_fingerprint = [String((chargeA && chargeA.json.status) || ''), String((chargeB && chargeB.json.status) || ''), aSnippet, bSnippet].join('|');

return [
  {
    json: {
      outcome,
      proof_check_id: 'proof_merge_complete',
      proof_check_name: 'Merge + proof check',
      recorded_at: new Date().toISOString(),
      wave_run_id: String(packet.wave_run_id || ''),
      reason,
      merge_fingerprint,
      topic: String(packet.topic || ''),
      charge_a_status: String((chargeA && chargeA.json.status) || ''),
      charge_b_status: String((chargeB && chargeB.json.status) || ''),
      proof_job: String(packet.proof_job || ''),
    },
  },
];
